// SCHOLAR — an open tome with gold trim, ruled pages and a floating shard of
// knowledge sparkling above the corner.
defineIcon('ability_g_scholar', '#5a4a1a', (p) => {
  p.glow(11.5, 3.5, 3, P.shardL, 0.3, 3);
  // book body with a soft top->bottom page gradient
  p.gradV(4, 4, 8, 9, P.bone, darken(P.bone, 0.18));
  p.rect(4, 4, 8, 2, P.gold);          // top trim
  p.hline(4, 11, 4, P.goldL);          // lit top edge
  p.vline(5, 11, 8, P.goldD);          // spine
  p.vline(4, 12, 4, darken(P.bone, 0.3)); // left page shadow
  for (let y = 6; y <= 10; y += 2) p.hline(6, 10, y, P.goldD); // ruled lines
  p.px(6, 11, darken(P.bone, 0.25));
  // floating knowledge shard + glints
  p.px(11, 3, P.shardL); p.px(12, 4, P.shardL); p.px(12, 3, P.white);
  p.star4(12, 4, 2, withAlpha(P.shard, 0.85), P.white);
});

// IRON SKIN — a heavy riveted shield-plate, beveled with a steel sheen and a
// bright top rim, grounded by a cool steel glow.
defineIcon('ability_g_iron_skin', P.blueD, (p) => {
  p.glow(8, 8, 5.5, P.steelL, 0.16, 3);
  for (let y = 3; y <= 12; y++) {
    const t = (y - 3) / 9;
    const w = 4.2 * (1 - t * 0.55) * (y > 9 ? (13 - y) / 3.5 : 1);
    // 3-tone vertical shading: lit upper / mid / shadowed lower
    const col = t < 0.28 ? P.steelL : t < 0.55 ? P.steel : P.steelD;
    p.hline(8 - w, 7 + w, y, col);
  }
  p.hline(5, 10, 3, P.steelL);   // top rim highlight
  p.vline(4, 9, 8, P.steelL);    // central ridge sheen
  p.hline(5, 10, 12, P.iron);    // bottom shade
  // rivets
  p.px(6, 5, P.gray4); p.px(10, 5, P.gray4);
  p.px(8, 7, P.glint); p.px(8, 7, P.gray4);
  p.sparkle(10, 4, P.hiSky, 1);
});

